222	/// Permanent sanity check for the `main`-bookmark tracking state
223	/// in both repos of the dual-repo workspace. Prints one line on
224	/// entry and one on exit of every command. If entry and exit
225	/// differ, the executing command is the culprit; if entry differs
226	/// from the previous command's exit, something *between*
227	/// invocations broke it. Originally added in 0.37.2 as a temporary
228	/// diagnostic; promoted to permanent in 0.37.4 after the user
229	/// reported "happens more than once" — the signal is worth keeping
230	/// in place until confidence in its correctness is well-established
231	/// across varied use, at which point a "silent when clean"
232	/// refinement would remove the steady-state noise without losing
233	/// detection value (see `notes/todo.md`).
234	///
235	/// Walks up from cwd to locate the workspace root (the directory
236	/// whose `.vc-config.toml` has `path = "/"`), then probes `<root>`
237	/// and `<root>/.claude`. Same labeling whether the user runs from
238	/// the app root, from `.claude`, or from any subdir.
239	fn bm_track(phase: &str, command_name: &str) {
240	    let header = format!("bm-track {phase} vc-x1 {command_name}");
241	    let root = match common::find_workspace_root() {
242	        Some(r) => r,
243	        None => {
244	            log::info!("{header}: no-workspace");
245	            return;
246	        }
247	    };
248	    let repos: [(std::path::PathBuf, &str); 2] =
249	        [(root.clone(), "app"), (root.join(".claude"), ".claude")];
250	    let mut parts: Vec<String> = Vec::new();
251	    for (repo, label) in repos {
252	        if !repo.join(".jj").exists() {
253	            parts.push(format!("{label}(main)=no-jj"));
254	            continue;
255	        }
256	        match bm_track_one(&repo, "main", "origin") {
257	            Ok(true) => parts.push(format!("{label}(main)=tracked")),
258	            Ok(false) => parts.push(format!("{label}(main)=NOT_TRACKED")),
259	            Err(e) => parts.push(format!(
260	                "{label}(main)=err({})",
261	                e.lines().next().unwrap_or("")
262	            )),
263	        }
264	    }
265	    log::info!("{header}: {}", parts.join(", "));
266	}
267	
268	/// Query jj for whether `bookmark` in `repo` is tracking `remote`.
269	/// Returns `Ok(true)` if the tracked-list entry for `bookmark` shows
270	/// an `@<remote>` line (in any form — `@origin:` when synced, or
271	/// `@origin (ahead by N commits):` / similar when divergent — both
272	/// still count as tracking). `Ok(false)` when no such line exists
273	/// (bookmark isn't tracking this remote or doesn't exist). `Err` on
274	/// subprocess failure.
275	fn bm_track_one(repo: &Path, bookmark: &str, remote: &str) -> Result<bool, String> {
276	    let repo_str = repo.to_string_lossy();
277	    let output = std::process::Command::new("jj")
278	        .args(["bookmark", "list", "--tracked", bookmark, "-R", &repo_str])
279	        .output()
280	        .map_err(|e| format!("spawn: {e}"))?;
281	    if !output.status.success() {
282	        return Err(String::from_utf8_lossy(&output.stderr).trim().to_string());
283	    }
284	    let stdout = String::from_utf8_lossy(&output.stdout);
285	    // Accept both the synced form (`@origin:`) and the decorated
286	    // divergent form (`@origin (ahead by N commits):`), which still
287	    // represents a tracking relationship.
288	    let colon = format!("@{remote}:");
289	    let paren = format!("@{remote} ");
290	    Ok(stdout.lines().any(|l| {
291	        let t = l.trim_start();
292	        t.starts_with(&colon) || t.starts_with(&paren)
293	    }))
294	}
