1	//! `chid` subcommand — print the short change ID of each commit in a
2	//! revision range, one per line (script-friendly output).
3	//!
4	//! - `ChidArgs`: clap surface; flattens
5	//!   `options_flags::common_args::CommonArgs`.
6	//! - `ChidParams`: clap-free; embeds `common::CommonParams`. Built
7	//!   via `TryFrom<&ChidArgs>` at the binary edge.
8	//! - `chid(&Context, &ChidParams)`: the op — `for_each_repo` + print
9	//!   `format_chid`.
10	
11	use clap::Args;
12	use jj_lib::repo::Repo;
13	use log::{debug, info};
14	
15	use crate::common::{self, CommonParams};
16	use crate::context::Context;
17	use crate::options_flags::common_args::CommonArgs;
18	
19	/// CLI args for `chid` — just the shared read-only commit-query args.
20	#[derive(Args, Debug)]
21	pub struct ChidArgs {
22	    #[command(flatten)]
23	    pub common: CommonArgs,
24	}
25	
26	/// Clap-free params for `chid`; embeds resolved `CommonParams`.
27	#[derive(Debug)]
28	pub struct ChidParams {
29	    pub common: CommonParams,
30	}
31	
32	impl TryFrom<&ChidArgs> for ChidParams {
33	    type Error = String;
34	
35	    /// Resolve clap `ChidArgs` into `ChidParams` by delegating to
36	    /// `CommonParams::try_from`; `chid` has no fields beyond
37	    /// `CommonArgs`.
38	    fn try_from(a: &ChidArgs) -> Result<Self, String> {
39	        Ok(ChidParams {
40	            common: CommonParams::try_from(&a.common)?,
41	        })
42	    }
43	}
44	
45	/// Print the short change ID of each commit in the resolved range.
46	///
47	/// `_ctx` is unused (chid has no user-config or `--log` consumer);
48	/// it's present for the uniform subcommand-layer signature.
49	pub fn chid(_ctx: &Context, params: &ChidParams) -> Result<(), Box<dyn std::error::Error>> {
50	    debug!("chid: enter");
51	    let c = &params.common;
52	    common::for_each_repo(&c.repos, &c.header, |workspace, repo| {
53	        let (ids, _) = common::collect_ids(
54	            workspace,
55	            repo,
56	            &c.spec.rev,
57	            c.spec.desc_count,
58	            c.spec.anc_count,
59	        )?;
60	        for commit_id in &ids {
61	            let commit = repo.store().get_commit(commit_id)?;
62	            info!("{}", common::format_chid(&commit));
63	        }
64	        Ok(())
65	    })?;
66	    debug!("chid: exit");
67	    Ok(())
68	}
69	
