        let c = parse(&["vc-x1", "chid", "-R", "../foo", "-s", "bot"]);
        assert_eq!(c.repo, Some(PathBuf::from("../foo")));
        assert_eq!(c.scope, Some(Scope::Roles(vec![Side::Bot])));
    }

    #[test]
