    fn label_default() {
        let c = parse(&["vc-x1", "chid"]);
        assert_eq!(c.label, "===");
        assert!(!c.no_label);
    }

    #[test]
    fn label_custom() {
        let c = parse(&["vc-x1", "chid", "-l", "---"]);
        assert_eq!(c.label, "---");
    }

    #[test]
    fn no_label() {
        let c = parse(&["vc-x1", "chid", "-L"]);
        assert!(c.no_label);
    }

