    fn params_from_args_defaults() {
        // ChidParams::try_from goes through the binary-edge resolution:
        // resolve_spec + resolve_header + resolve_repos.
        use super::ChidParams;
        let cli = Cli::try_parse_from(["vc-x1", "chid"]).unwrap();
