        };
        let params = ChidParams::try_from(&args).unwrap();
        // default: no flags → repos resolves to [.]
        assert_eq!(params.common.repos, vec![PathBuf::from(".")]);
        // default revision @
        assert_eq!(params.common.spec.rev, "@");
    }
}

