//! `Subcommand` trait — collapse per-arm dispatch boilerplate in
//! `main.rs`. Each subcommand's `Args` type implements
//! `Subcommand`; the trait's default `dispatch` method does the
//! `Context::load` → `to_params` → `run` → `ExitCode` plumbing,
//! so each `Commands::Foo(args) => …` arm collapses to a single
//! `args.dispatch(cli.log)` call.
//!
//! - `to_params(&self) -> Result<Self::Params, String>` — total
//!   `From` impls return `Ok(...)`; fallible `TryFrom` impls
//!   forward their error. Uniform `String` error type matches
//!   the existing `CommonParams::try_from` / `FinalizeParams`
//!   precedent.
//! - `run(ctx, params)` is an associated function (no `&self`) —
//!   `params` carries everything the body needs.
//! - `suppress_banner` / `is_detached_exec` — `false`-default
//!   peek hooks. `chid` / `desc` / `list` / `show` override
//!   `suppress_banner`; `finalize` overrides `is_detached_exec`.
//!
//! Introduced in the `0.50.0` cycle; `chid` is the worked
//! example. The trait coexists with `clap::Subcommand` (the
//! derive macro on `enum Commands`) — `main.rs` qualifies the
//! clap derive at the use site (`#[derive(clap::Subcommand, …)]`)
//! to free the unqualified `Subcommand` name for this trait.

use std::path::PathBuf;
use std::process::ExitCode;

use log::error;

use crate::context::Context;

/// Trait implemented by every subcommand's clap `Args` type so
/// `main.rs` can dispatch via a single `args.dispatch(cli.log)`
/// call instead of repeating the load / params / run / exit
/// boilerplate.
pub trait Subcommand: Sized {
    /// The clap-free `Params` struct the subcommand body
    /// consumes.
    type Params;

    /// Build `Params` from `Args` at the binary edge. The
    /// `Result` shape absorbs both `From` (return `Ok(...)`)
    /// and `TryFrom` (forward the error) impls uniformly.
    fn to_params(&self) -> Result<Self::Params, String>;

    /// Run the subcommand body.
    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>>;

    /// Whether to suppress the leading banner line. Default
    /// `false`; subcommands with a `-L` / `--no-label`
    /// script-friendly mode override.
    fn suppress_banner(&self) -> bool {
        false
    }

    /// Whether this invocation is the detached
    /// `finalize --exec` re-entry. Default `false`; `finalize`
    /// overrides.
    fn is_detached_exec(&self) -> bool {
        false
    }

    /// Default dispatch: `Context::load(log)` → `to_params(&self)`
    /// → `run(&ctx, &params)` → `ExitCode`. Replaces the per-arm
    /// boilerplate in `main.rs`.
    fn dispatch(&self, log: Option<PathBuf>) -> ExitCode {
        let ctx = match Context::load(log) {
            Ok(c) => c,
            Err(e) => {
                error!("{e}");
                return ExitCode::FAILURE;
            }
        };
        let params = match self.to_params() {
            Ok(p) => p,
            Err(e) => {
                error!("{e}");
                return ExitCode::FAILURE;
            }
        };
        match Self::run(&ctx, &params) {
            Ok(()) => ExitCode::SUCCESS,
            Err(e) => {
                error!("{e}");
                ExitCode::FAILURE
            }
        }
    }
}

