// main.rs — global, near BANNER + bm_track
pub fn sb_ide(suppress_banner: bool, is_detached_exec: bool) {
    if !is_detached_exec {
        if !suppress_banner {
            log::info!("{BANNER}");
        }
        finalize::surface_previous_failures();
