```rust
// subcommand.rs — peek methods on the trait, default false, take &Params
pub trait SubcommandRunner {
    type Params;
    fn to_params(&self) -> Result<Self::Params, String>;
    fn run(ctx: &Context, params: &Self::Params)
        -> Result<(), Box<dyn std::error::Error>>;

    fn suppress_banner(_params: &Self::Params) -> bool { false }
    fn is_detached_exec(_params: &Self::Params) -> bool { false }

    fn dispatch(&self, log: Option<PathBuf>) -> ExitCode {
        let ctx = /* … */;
        let params = /* …, fallible via to_params … */;
        crate::sb_ide(
            Self::suppress_banner(&params),
            Self::is_detached_exec(&params),
        );
        match Self::run(&ctx, &params) { /* … */ }
    }
}
```

